# SparkTokenPrimitivesError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class SparkTokenPrimitivesError(Exception):
    pass

_UniffiTempSparkTokenPrimitivesError = SparkTokenPrimitivesError

class SparkTokenPrimitivesError:  # type: ignore
    class Spark(_UniffiTempSparkTokenPrimitivesError):

        def __repr__(self):
            return "SparkTokenPrimitivesError.Spark({})".format(repr(str(self)))
    _UniffiTempSparkTokenPrimitivesError.Spark = Spark # type: ignore

SparkTokenPrimitivesError = _UniffiTempSparkTokenPrimitivesError # type: ignore
del _UniffiTempSparkTokenPrimitivesError


class _UniffiConverterTypeSparkTokenPrimitivesError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return SparkTokenPrimitivesError.Spark(
                _UniffiConverterString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, SparkTokenPrimitivesError.Spark):
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, SparkTokenPrimitivesError.Spark):
            buf.write_i32(1)



class _UniffiConverterOptionalBytes(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiConverterBytes.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiConverterBytes.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiConverterBytes.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")



class _UniffiConverterSequenceBytes(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        for item in value:
            _UniffiConverterBytes.check_lower(item)

    @classmethod
    def write(cls, value, buf):
        items = len(value)
        buf.write_i32(items)
        for item in value:
            _UniffiConverterBytes.write(item, buf)

    @classmethod
    def read(cls, buf):
        count = buf.read_i32()
        if count < 0:
            raise InternalError("Unexpected negative sequence length")

        return [
            _UniffiConverterBytes.read(buf) for i in range(count)
        ]



